import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class FileTypeIcon extends StatelessWidget { final String mimeType; final double size; const FileTypeIcon({super.key, required this.mimeType, this.size = 24}); @override Widget build(BuildContext context) { IconData icon; Color color; if (mimeType.startsWith('image/')) { icon = Icons.image_outlined; color = Colors.blue; } else if (mimeType.startsWith('video/')) { icon = Icons.videocam_outlined; color = Colors.purple; } else if (mimeType.contains('pdf')) { icon = Icons.picture_as_pdf_outlined; color = AppTheme.errorColor; } else if (mimeType.startsWith('audio/')) { icon = Icons.audiotrack_outlined; color = Colors.green; } else { icon = Icons.attach_file_outlined; color = AppTheme.primaryColor; } return Icon(icon, color: color, size: size); } }